	runGitInteg(t, secondDir, "push", "origin", "main")

	require.NoError(t, os.WriteFile(filepath.Join(workDir, "operator.txt"), []byte("operator\n"), 0o644))
	runGitInteg(t, workDir, "add", "operator.txt")

	ops := RealLandingGitOps{}
